module float_multi(
    input clk,
    input rst,
    input [31:0] a,
    input [31:0] b,
    output reg [31:0] z
);

    reg [2:0] counter;
    reg [23:0] a_mantissa, b_mantissa, z_mantissa;
    reg [9:0] a_exponent, b_exponent, z_exponent;
    reg a_sign, b_sign, z_sign;
    reg [49:0] product;
    reg guard_bit, round_bit, sticky;

    always @(posedge clk) begin
        if (rst) begin
            counter <= 0;
            z <= 0;
        end else begin
            case (counter)
                // Stage 0: Extract fields from inputs
                3'd0: begin
                    a_mantissa <= {1'b1, a[22:0]};
                    b_mantissa <= {1'b1, b[22:0]};
                    a_exponent <= {2'b00, a[30:23]};
                    b_exponent <= {2'b00, b[30:23]};
                    a_sign <= a[31];
                    b_sign <= b[31];
                    counter <= 1;
                end

                // Stage 1: Handle special cases and normalize
                3'd1: begin
                    // Check for NaN
                    if ((a_exponent[7:0] == 8'hFF && a_mantissa[22:0] != 0) ||
                        (b_exponent[7:0] == 8'hFF && b_mantissa[22:0] != 0)) begin
                        // Result is NaN
                        z <= 32'h7FC00000;
                        counter <= 0;
                    end
                    // Check for infinity
                    else if (a_exponent[7:0] == 8'hFF || b_exponent[7:0] == 8'hFF) begin
                        // Check if other operand is zero
                        if ((a_exponent[7:0] == 8'h00 && a_mantissa[22:0] == 0) ||
                            (b_exponent[7:0] == 8'h00 && b_mantissa[22:0] == 0)) begin
                            // Infinity * 0 = NaN
                            z <= 32'h7FC00000;
                        end else begin
                            // Result is infinity
                            z <= {a_sign ^ b_sign, 8'hFF, 23'h0};
                        end
                        counter <= 0;
                    end
                    // Check for zero
                    else if ((a_exponent[7:0] == 8'h00) || (b_exponent[7:0] == 8'h00)) begin
                        z <= {a_sign ^ b_sign, 31'h0};
                        counter <= 0;
                    end
                    else begin
                        z_sign <= a_sign ^ b_sign;
                        z_exponent <= a_exponent + b_exponent - 10'd127;
                        counter <= 2;
                    end
                end

                // Stage 2: Multiply mantissas
                3'd2: begin
                    product <= a_mantissa * b_mantissa;
                    counter <= 3;
                end

                // Stage 3: Normalize product
                3'd3: begin
                    if (product[47]) begin
                        // Shift right by 1
                        z_mantissa <= product[47:24];
                        guard_bit <= product[23];
                        round_bit <= product[22];
                        sticky <= |product[21:0];
                        z_exponent <= z_exponent + 1;
                    end else begin
                        // No shift needed
                        z_mantissa <= product[46:23];
                        guard_bit <= product[22];
                        round_bit <= product[21];
                        sticky <= |product[20:0];
                    end
                    counter <= 4;
                end

                // Stage 4: Rounding
                3'd4: begin
                    // Round to nearest even
                    if (guard_bit && (round_bit || sticky || z_mantissa[0])) begin
                        z_mantissa <= z_mantissa + 1;
                        // Check if mantissa overflowed
                        if (z_mantissa == 24'hFFFFFF) begin
                            z_exponent <= z_exponent + 1;
                        end
                    end
                    counter <= 5;
                end

                // Stage 5: Output generation
                3'd5: begin
                    // Check for overflow
                    if (z_exponent >= 10'h0FF) begin
                        // Overflow -> infinity
                        z <= {z_sign, 8'hFF, 23'h0};
