    parameter S0 = 3'd0; // Initial state
    parameter S1 = 3'd1; // Received '1'
    parameter S2 = 3'd2; // Received '10'
    parameter S3 = 3'd3; // Received '100'
    parameter S4 = 3'd4; // Received '1001'
    parameter S5 = 3'd5; // Received '10011' (match)

    reg [2:0] current_state, next_state;

    // State register
    always @(posedge CLK or posedge RST) begin
        if (RST) begin
            current_state <= S0;
        end else begin
            current_state <= next_state;
        end
    end

    // Next state logic (Mealy FSM)
    always @(*) begin
        case (current_state)
            S0: begin
                if (IN == 1'b1)
                    next_state = S1;
                else
                    next_state = S0;
            end
            S1: begin
                if (IN == 1'b0)
                    next_state = S2;
                else
                    next_state = S1;
            end
            S2: begin
                if (IN == 1'b0)
                    next_state = S3;
                else
                    next_state = S1;
            end
            S3: begin
                if (IN == 1'b1)
                    next_state = S4;
                else
                    next_state = S0;
            end
            S4: begin
                if (IN == 1'b1)
                    next_state = S5;
                else
                    next_state = S2;
