module freq_divbyfrac(
    input clk,
    input rst_n,
    output clk_div
);

    // Parameter for 3.5x division (7 cycles total with double-edge technique)
    parameter MUL2_DIV_CLK = 7;

    // Counter
    reg [2:0] cnt;

    // Intermediate clock signals
    reg clk_div1;
    reg clk_div2;

    // Counter logic
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            cnt <= 3'd0;
        end else begin
            if (cnt == MUL2_DIV_CLK - 1) begin
                cnt <= 3'd0;
            end else begin
                cnt <= cnt + 3'd1;
            end
        end
    end

    // Generate first divided clock (posedge triggered)
    // High for 4 cycles, low for 3 cycles (or similar pattern for 3.5)
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            clk_div1 <= 1'b0;
        end else begin
            if (cnt == 3'd0) begin
                clk_div1 <= 1'b1;
            end else if (cnt == 3'd3) begin
                clk_div1 <= 1'b0;
            end
        end
    end

    // Generate second divided clock (negedge triggered, phase shifted by half cycle)
    always @(negedge clk or negedge rst_n) begin
        if (!rst_n) begin
            clk_div2 <= 1'b0;
        end else begin
            if (cnt == 3'd0) begin
                clk_div2 <= 1'b1;
            end else if (cnt == 3'd3) begin
                clk_div2 <= 1'b0;
            end
        end
    end

    // OR the two clocks to produce fractional divided clock
    assign clk_div = clk_div1 | clk_div2;

endmodule

